import{_ as e,c as a,o,U as r}from"./chunks/framework.9QHaLlVJ.js";const u=JSON.parse('{"title":"PHP面试题","description":"","frontmatter":{},"headers":[],"relativePath":"doc/编程语言/PHP/实战/PHP面试题.md","filePath":"packages/doc/src/编程语言/PHP/实战/PHP面试题.md","lastUpdated":1707061484000}'),t={name:"doc/编程语言/PHP/实战/PHP面试题.md"},c=r('<h1 id="php面试题" tabindex="-1">PHP面试题 <a class="header-anchor" href="#php面试题" aria-label="Permalink to &quot;PHP面试题&quot;">​</a></h1><h2 id="_1-php数组底层的实现原理" tabindex="-1">1.PHP数组底层的实现原理？ <a class="header-anchor" href="#_1-php数组底层的实现原理" aria-label="Permalink to &quot;1.PHP数组底层的实现原理？&quot;">​</a></h2><h2 id="_2-php适合做守护进程吗-为什么" tabindex="-1">2.PHP适合做守护进程吗？为什么？ <a class="header-anchor" href="#_2-php适合做守护进程吗-为什么" aria-label="Permalink to &quot;2.PHP适合做守护进程吗？为什么？&quot;">​</a></h2><h2 id="_3-fpm进程原理" tabindex="-1">3.FPM进程原理？ <a class="header-anchor" href="#_3-fpm进程原理" aria-label="Permalink to &quot;3.FPM进程原理？&quot;">​</a></h2><h2 id="_4-trait作用" tabindex="-1">4.Trait作用 <a class="header-anchor" href="#_4-trait作用" aria-label="Permalink to &quot;4.Trait作用&quot;">​</a></h2><p>php本身是单继承语言，Trait是一种代码复用机制，间接实现多继承</p><h2 id="_5-php的类加载机制" tabindex="-1">5.php的类加载机制？ <a class="header-anchor" href="#_5-php的类加载机制" aria-label="Permalink to &quot;5.php的类加载机制？&quot;">​</a></h2><p>require</p><p>require_once</p><p>include</p><p>include_once</p><p>__autoload()</p><p>Spl_aotoload_register()</p><ul><li><strong>incluce</strong> 在用到时加载</li><li><strong>require</strong> 在一开始就加载</li><li><strong>_once</strong> 后缀表示已加载的不加载</li></ul><p><strong>include</strong> 引入文件的时候，如果碰到错误，会给出提示，并继续运行下边的代码。</p><p><strong>require</strong> 引入文件的时候，如果碰到错误，会给出提示，并停止运行下边的代码。</p><h2 id="_6-php-的composer原理" tabindex="-1">6.PHP 的composer原理？ <a class="header-anchor" href="#_6-php-的composer原理" aria-label="Permalink to &quot;6.PHP 的composer原理？&quot;">​</a></h2><p><a href="https://segmentfault.com/a/1190000014948542" target="_blank" rel="noreferrer">https://segmentfault.com/a/1190000014948542</a></p><p>在 PHP 开发过程中，如果希望从外部引入一个 Class ，通常会使用 <code>include</code> 和 <code>require</code> 方法，去把定义这个 Class 的文件包含进来。这个在小规模开发的时候，没什么大问题。但在大型的开发项目中，使用这种方式会带来一些隐含的问题：如果一个 PHP 文件需要使用很多其它类，那么就需要很多的 <code>require/include</code> 语句，这样有可能会 <strong>造成遗漏</strong> 或者 <strong>包含进不必要的类文件</strong>。如果大量的文件都需要使用其它的类，那么要保证每个文件都包含正确的类文件肯定是一个噩梦， 况且 require或 incloud 的性能代价很大。</p><p>PHP5 为这个问题提供了一个解决方案，这就是 <code>类的自动加载(autoload)机制</code>。<code>autoload机制</code> 可以使得 PHP 程序有可能在使用类时才自动包含类文件，而不是一开始就将所有的类文件<code>include</code>进来，这种机制也称为 <code>Lazy loading (惰性加载)</code>。</p><p>总结起来，自动加载功能带来了几处优点：</p><p>1.使用类之前无需 <code>include / require</code></p><p>2.使用类的时候才会 <code>include / require</code> 文件，实现了 <code>lazy loading</code> ，避免了 <code>include / require</code> 多余文件。</p><p>3.无需考虑引入 <strong>类的实际磁盘地址</strong> ，实现了逻辑和实体文件的分离</p>',24),p=[c];function d(i,n,l,s,h,P){return o(),a("div",null,p)}const m=e(t,[["render",d]]);export{u as __pageData,m as default};
